import axios from 'axios';
import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const PortfolioList = () => {
    const [works, setWorks] = useState([]); // Список работ
    const [categories, setCategories] = useState([]); // Список категорий
    const [selectedCategory, setSelectedCategory] = useState(''); // Фильтр по категории
    const [currentPage, setCurrentPage] = useState(1); // Текущая страница
    const [isLoading, setIsLoading] = useState(true); // Флаг загрузки

    // Загрузка списка работ
    useEffect(() => {
        fetchWorks(currentPage);
    }, [currentPage, selectedCategory]);

    const fetchWorks = async (page = 1) => {
        setIsLoading(true);
        try {
            const queryParam = selectedCategory ? `?category=${selectedCategory}` : '';
            const response = await axios.get(
                `${process.env.REACT_APP_API_URL}/api/portfolio/${queryParam}`
            );

            setWorks(response.data); // Чистый массив данных
        } catch (error) {
            console.error('Error fetching portfolio works:', error);
            setWorks([]); // Пустой массив при ошибке
        } finally {
            setIsLoading(false);
        }
    };

    // Загрузка категорий
    useEffect(() => {
        const fetchCategories = async () => {
            try {
                const response = await axios.get(
                    `${process.env.REACT_APP_API_URL}/api/portfolio/categories/`
                );
                setCategories(response.data);
            } catch (error) {
                console.error('Error fetching categories:', error);
            }
        };

        fetchCategories();
    }, []);

    return (
        <div>
            <h1>Portfolio</h1>

            {/* Фильтр по категориям */}
            <label>Filter by Category: </label>
            <select
                value={selectedCategory}
                onChange={(e) => {
                    setSelectedCategory(e.target.value);
                    setCurrentPage(1); // Сбросить пагинацию
                }}
            >
                <option value="">All</option>
                {categories.map((category) => (
                    <option key={category.id} value={category.id}>
                        {category.name}
                    </option>
                ))}
            </select>

            {/* Список работ */}
            {isLoading ? (
                <p>Loading...</p>
            ) : works.length > 0 ? (
                works.map((work) => (
                    <div key={work.id} style={{ margin: '20px 0', border: '1px solid #ddd', padding: '10px' }}>
                        <h3>{work.name}</h3>
                        <p><strong>Description:</strong> {work.description}</p>
                        <p><strong>Type:</strong> {work.type}</p>
                        {work.image && (
                            <img
                                src={`${process.env.REACT_APP_API_URL}${work.image}`}
                                alt={work.name}
                                width="200"
                            />
                        )}
                        {work.video_url && (
                            <div>
                                <iframe
                                    width="300"
                                    height="200"
                                    src={work.video_url}
                                    title={work.name}
                                    frameBorder="0"
                                    allowFullScreen
                                ></iframe>
                            </div>
                        )}
                        <Link to={`/portfolio/${work.id}`}>View Details</Link>
                    </div>
                ))
            ) : (
                <p>No works found.</p>
            )}
        </div>
    );
};

export default PortfolioList;
